import { getStageConfig, type StageConfig } from '../config/stages'
import { isBossStage } from '../config/gameplay'
import type { UpgradeLevels } from '../../services/shopService'
import { generateRunModifierOffer } from './runModifierSystem'

export type ProgressionResult = {
  enterShop: boolean
  enterBossFight: boolean
  nextStage: number
  nextStageConfig: StageConfig
}

export function evaluateStageProgression(
  currentStage: number,
  enemiesRemaining: number,
  bossActive = false,
  bossDefeated = false
): ProgressionResult {
  if (enemiesRemaining > 0) {
    return {
      enterShop: false,
      enterBossFight: false,
      nextStage: currentStage,
      nextStageConfig: getStageConfig(currentStage)
    }
  }

  const bossStage = isBossStage(currentStage)

  if (!bossStage) {
    const nextStage = currentStage + 1
    return {
      enterShop: true,
      enterBossFight: false,
      nextStage,
      nextStageConfig: getStageConfig(nextStage)
    }
  }

  if (!bossActive) {
    return {
      enterShop: false,
      enterBossFight: true,
      nextStage: currentStage,
      nextStageConfig: getStageConfig(currentStage)
    }
  }

  if (!bossDefeated) {
    return {
      enterShop: false,
      enterBossFight: false,
      nextStage: currentStage,
      nextStageConfig: getStageConfig(currentStage)
    }
  }

  const nextStage = currentStage + 1

  return {
    enterShop: true,
    enterBossFight: false,
    nextStage,
    nextStageConfig: getStageConfig(nextStage)
  }
}

export function createShopRunModifierOffer(input: {
  runId: string
  runSeed: string
  stageNumber: number
  upgradeLevels: UpgradeLevels
}) {
  return generateRunModifierOffer({
    runId: input.runId,
    stageNumber: input.stageNumber,
    runSeed: input.runSeed,
    upgradeLevels: input.upgradeLevels
  })
}

import { createBossForStage, tickBossAttackTimer, type BossEntity } from '../entities/boss'
import type { WaveState } from './waveSystem'

export function spawnBossForWave(wave: WaveState, attempt = 1): WaveState {
  if (wave.boss || wave.enemies.length > 0) {
    return wave
  }

  return {
    ...wave,
    boss: createBossForStage(wave.stage, attempt)
  }
}

export function tickBoss(wave: WaveState, deltaSeconds: number, canvasWidth: number): WaveState {
  if (!wave.boss) {
    return wave
  }

  const movedBoss = {
    ...wave.boss,
    x: wave.boss.x + wave.boss.velocityX * deltaSeconds
  }

  const clampedX = Math.max(0, Math.min(canvasWidth - movedBoss.width, movedBoss.x))
  const hitBorder = clampedX !== movedBoss.x
  const bouncedBoss = {
    ...movedBoss,
    x: clampedX,
    velocityX: hitBorder ? movedBoss.velocityX * -1 : movedBoss.velocityX
  }

  return {
    ...wave,
    boss: tickBossAttackTimer(bouncedBoss, deltaSeconds)
  }
}

export function applyBossDamage(boss: BossEntity, damage: number): BossEntity {
  const nextHealth = Math.max(0, boss.health - damage)
  return {
    ...boss,
    health: nextHealth
  }
}

export function isBossDefeated(wave: WaveState): boolean {
  return Boolean(wave.boss && wave.boss.health <= 0)
}

import { getCycleIndex } from '../config/gameplay'
import { logTelemetryEvent } from '../../lib/telemetry'

export type BossTelemetryBase = {
  stage: number
  bossId: string
  attempt: number
  bossHealthMax: number
}

const emittedEvents = new Set<string>()

function eventKey(event: string, base: BossTelemetryBase): string {
  return `${event}:${base.stage}:${base.attempt}`
}

async function emitOnce(event: string, payload: Record<string, string | number | boolean>): Promise<boolean> {
  const key = eventKey(event, {
    stage: Number(payload.stage),
    bossId: String(payload.bossId),
    attempt: Number(payload.attempt),
    bossHealthMax: Number(payload.bossHealthMax ?? 0)
  })

  if (emittedEvents.has(key)) {
    return false
  }

  emittedEvents.add(key)
  const logged = await logTelemetryEvent(event, payload)

  if (!logged) {
    emittedEvents.delete(key)
  }

  return logged
}

export async function emitBossEncounterStarted(base: BossTelemetryBase): Promise<boolean> {
  return emitOnce('boss_encounter_started', {
    stage: base.stage,
    bossId: base.bossId,
    attempt: base.attempt,
    cycle: getCycleIndex(base.stage),
    bossHealthMax: base.bossHealthMax
  })
}

export async function emitBossPlayerDefeated(base: BossTelemetryBase): Promise<boolean> {
  return emitOnce('boss_player_defeated', {
    stage: base.stage,
    bossId: base.bossId,
    attempt: base.attempt,
    cycle: getCycleIndex(base.stage),
    bossHealthMax: base.bossHealthMax
  })
}

export async function emitBossPlayerVictory(base: BossTelemetryBase): Promise<boolean> {
  return emitOnce('boss_player_victory', {
    stage: base.stage,
    bossId: base.bossId,
    attempt: base.attempt,
    cycle: getCycleIndex(base.stage),
    bossHealthMax: base.bossHealthMax
  })
}

export function resetBossTelemetryDedupe(): void {
  emittedEvents.clear()
}

export const BOSS_STAGE_INTERVAL = 10
export const CAMPAIGN_BOSS_STAGE_MAX = 5

export const RARE_DROP_CHANCE_PERCENT = 8

export const RARE_DROP_LIFETIME_MS = 8000

export const BOSS_HORIZONTAL_SPEED = 90

export const CYCLE_DIFFICULTY_STEP = 0.1

export function isBossStage(stage: number): boolean {
  if (stage < 1) {
    return false
  }

  if (stage <= CAMPAIGN_BOSS_STAGE_MAX) {
    return true
  }

  return stage % BOSS_STAGE_INTERVAL === 0
}

export function getCycleIndex(stage: number): number {
  if (stage < 1) {
    return 0
  }

  return Math.floor((stage - 1) / BOSS_STAGE_INTERVAL)
}

export function getCycleDifficultyMultiplier(stage: number): number {
  return 1 + getCycleIndex(stage) * CYCLE_DIFFICULTY_STEP
}

import { saveLocalHighscore } from '../services/highscoreService'
import { logTelemetryEvent } from '../lib/telemetry'
import {
  getPersistedProgressProfile,
  savePersistedProgressProfile
} from '../services/shopPersistenceService'
import type { UpgradeLevels } from '../services/shopService'
import { getCycleIndex, isBossStage } from './config/gameplay'
import { createEnemyGrid } from './entities/enemy'
import { clampActiveDropsByStage } from './config/performance'
import type { RareDropEntity } from './entities/dropItem'
import { createPlayer, movePlayer, tickPlayer, tryConsumeShot, type PlayerEntity } from './entities/player'
import {
  createHomingMissileProjectile,
  createLaserProjectile,
  createPlayerProjectile,
  steerHomingProjectiles,
  stepProjectiles,
  type ProjectileEntity
} from './entities/projectile'
import { createInputManager } from './input/inputManager'
import { createGameLoop, type GameLoopController } from './loop'
import { gameStore } from '../state/gameStore'
import {
  checkEnemyReachedPlayerLine,
  resolveBossProjectileCollisions,
  resolvePlayerDropCollisions,
  resolveEnemyProjectileHitsPlayer,
  resolvePlayerProjectileCollisions
} from './systems/collisionSystem'
import { emitBossProjectiles } from './systems/bossAttackSystem'
import { spawnBossForWave, tickBoss } from './systems/bossSystem'
import { removeExpiredDrops, resolveCollectedSpecialShot, stepDrops } from './systems/dropSystem'
import { createShopRunModifierOffer, evaluateStageProgression } from './systems/progressionSystem'
import { addOrRefreshPowerUp, getActiveWeaponPowerUp, removeExpiredPowerUps } from './systems/powerUpSystem'
import { updateScoreAndLives } from './systems/scoreLivesSystem'
import { applyPlayerUpgrades } from './systems/upgradeSystem'
import {
  applyWaveEnemies,
  createDropsFromDefeatedEnemies,
  emitEnemyProjectiles,
  stepEnemies,
