import { saveLocalHighscore } from '../services/highscoreService'
import { logTelemetryEvent } from '../lib/telemetry'
import {
  getPersistedProgressProfile,
  savePersistedProgressProfile
} from '../services/shopPersistenceService'
import type { UpgradeLevels } from '../services/shopService'
import { getCycleIndex, isBossStage } from './config/gameplay'
import { createEnemyGrid } from './entities/enemy'
import { clampActiveDropsByStage } from './config/performance'
import type { RareDropEntity } from './entities/dropItem'
import { createPlayer, movePlayer, tickPlayer, tryConsumeShot, type PlayerEntity } from './entities/player'
import {
  createHomingMissileProjectile,
  createLaserProjectile,
  createPlayerProjectile,
  steerHomingProjectiles,
  stepProjectiles,
  type ProjectileEntity
} from './entities/projectile'
import { createInputManager } from './input/inputManager'
import { createGameLoop, type GameLoopController } from './loop'
import { gameStore } from '../state/gameStore'
import {
  checkEnemyReachedPlayerLine,
  resolveBossProjectileCollisions,
  resolvePlayerDropCollisions,
  resolveEnemyProjectileHitsPlayer,
  resolvePlayerProjectileCollisions
} from './systems/collisionSystem'
import { emitBossProjectiles } from './systems/bossAttackSystem'
import { spawnBossForWave, tickBoss } from './systems/bossSystem'
import { removeExpiredDrops, resolveCollectedSpecialShot, stepDrops } from './systems/dropSystem'
import { createShopRunModifierOffer, evaluateStageProgression } from './systems/progressionSystem'
import { addOrRefreshPowerUp, getActiveWeaponPowerUp, removeExpiredPowerUps } from './systems/powerUpSystem'
import { updateScoreAndLives } from './systems/scoreLivesSystem'
import { applyPlayerUpgrades } from './systems/upgradeSystem'
import {
  applyWaveEnemies,
  createDropsFromDefeatedEnemies,
  emitEnemyProjectiles,
  stepEnemies,
  type WaveState
} from './systems/waveSystem'

let context: CanvasRenderingContext2D | null = null
let loopController: GameLoopController | null = null
const inputManager = createInputManager()
let player: PlayerEntity | null = null
let wave: WaveState = {
  stage: 1,
  enemies: createEnemyGrid(1),
  boss: null,
  direction: 1
}
let projectiles: ProjectileEntity[] = []
let activeDrops: RareDropEntity[] = []
let pendingStage: number | null = null
let currentRunId = 'run-0'
let currentRunSeed = 'seed-0'
let bossEncounterStartLives: number | null = null

type BossEncounterSnapshot = ReturnType<typeof gameStore.getState>['bossEncounter']

function getBossEncounterAttemptForStage(stage: number): number {
  const encounter = gameStore.getState().bossEncounter
  if (encounter.stage === stage) {
    return encounter.attempt + 1
  }

  return 1
}

function getBossEncounterProfileSnapshot() {
  if (!wave.boss) {
    return null
  }

  return {
    profileId: wave.boss.profileId,
    displayName: wave.boss.displayName,
    movementModel: wave.boss.movementModel,
    feedbackPreset: wave.boss.feedbackPreset,
    telegraphMs: wave.boss.telegraphMs,
    patternIds: [...wave.boss.patternIds]
  }
}

function createClearedBossEncounter(existing: BossEncounterSnapshot, partial?: Partial<BossEncounterSnapshot>): BossEncounterSnapshot {
  return {
    ...existing,
    active: false,
    lifecycle: 'idle',
    bossId: null,
    profile: null,
    health: 0,
    maxHealth: 0,
    ...partial
  }
}

function updateBossEncounterFromWave(partial?: Partial<BossEncounterSnapshot>): void {
  const state = gameStore.getState()
  const existing = state.bossEncounter
  const nextHealth = wave.boss?.health ?? 0
  const nextMaxHealth = wave.boss?.maxHealth ?? 0
  const livesBase = bossEncounterStartLives ?? state.lives

  gameStore.setState({
    bossEncounter: {
      ...existing,
      active: Boolean(wave.boss),
      lifecycle: wave.boss ? existing.lifecycle : existing.lifecycle === 'active' ? 'idle' : existing.lifecycle,
      bossId: wave.boss?.id ?? null,
      profile: getBossEncounterProfileSnapshot(),
      stage: wave.boss?.stage ?? existing.stage,
      health: nextHealth,
      maxHealth: nextMaxHealth,
      damageTaken: wave.boss ? Math.max(existing.damageTaken, livesBase - state.lives) : existing.damageTaken,
      ...partial
    }
  })
}

function startBossEncounter(nowMs: number): void {
  const state = gameStore.getState()
  bossEncounterStartLives = state.lives
  updateBossEncounterFromWave({
    stage: wave.stage,
    attempt: getBossEncounterAttemptForStage(wave.stage),
    startedAtMs: nowMs,
    endedAtMs: null,
    lifecycle: 'active',
    outcome: 'in-progress',
    damageTaken: 0
  })
}

function handleBossVictory(nowMs: number): void {
  const state = gameStore.getState()
  const livesBase = bossEncounterStartLives ?? state.lives

  gameStore.setState({
    bossEncounter: {
      ...state.bossEncounter,
      active: false,
      lifecycle: 'victory',
      endedAtMs: nowMs,
      outcome: 'victory',
      bossId: state.bossEncounter.bossId,
      profile: state.bossEncounter.profile,
      health: 0,
      maxHealth: state.bossEncounter.maxHealth,
      damageTaken: Math.max(state.bossEncounter.damageTaken, livesBase - state.lives)
    }
  })
  bossEncounterStartLives = null
}

function handleBossPlayerDefeat(nowMs: number): void {
  const state = gameStore.getState()
  const livesBase = bossEncounterStartLives ?? state.lives

  gameStore.setState({
    bossEncounter: {
      ...state.bossEncounter,
      active: false,
      lifecycle: 'defeat',
      endedAtMs: nowMs,
      outcome: 'defeat',
      damageTaken: Math.max(state.bossEncounter.damageTaken, livesBase - state.lives)
    }
  })
  bossEncounterStartLives = null
}

function syncStore(): void {
  const state = gameStore.getState()
  gameStore.setState({
    score: state.score,
    lives: state.lives,
    stage: wave.stage,
    bossEncounter: {
      ...state.bossEncounter,
      active: Boolean(wave.boss),
      lifecycle: wave.boss ? state.bossEncounter.lifecycle : state.bossEncounter.lifecycle === 'active' ? 'idle' : state.bossEncounter.lifecycle,
      bossId: wave.boss?.id ?? null,
      profile: getBossEncounterProfileSnapshot(),
      stage: wave.boss?.stage ?? state.bossEncounter.stage,
      health: wave.boss?.health ?? 0,
